// Safe JSON parsing function
function parseIfJson(value) {
    if (typeof value === "string") {
        try {
            return JSON.parse(value);
        } catch (e) {
            return {};
        }
    }
    if (typeof value === "object" && value !== null) {
        return value;
    }
    return {};
}

// Unified function to get the customer ID
function getCustomerId() {
    // Try private_detail_object first
    let customerObj = parseIfJson(Context.getVariable("private_detail_object"));
    let customer_id = customerObj.active_id;

    // Fallback to Application Input
    if (!customer_id) {
        const appInput = parseIfJson(Context.getVariable("Application Input"));
        customer_id = appInput.Uid;
    }

    // Fallback to Agentic context variable Uid
    if (!customer_id) {
        const agentUid = Context.getVariable("Uid");
        if (typeof agentUid === "string" && agentUid !== "null") {
            customer_id = agentUid;
        }
    }

    return customer_id;
}

// Main function to retrieve account details and balance information
function getAccountDetails(selectedAccountNumber) {
    let account_balance_information = "";

    // Get account list from context
    const accountList = Context.getVariable("account_list") || [];
    const last4 = String(selectedAccountNumber).slice(-4);

    // Determine channel type to switch formatting style
    const channelType = Context.getVariable("Channel Type");
    const isDigital = typeof channelType === "string" && channelType.trim().toLowerCase() === "digital";

    // Map of currency codes to symbols
    const currencyMap = {
        USD: "$",
        EUR: "€",
        GBP: "£",
        JPY: "¥",
        CNY: "¥",
        AUD: "A$",
        CAD: "C$"
    };

    // Find account matching the last 4 digits
    const account = accountList.find(acc => acc.accountNumber.endsWith(last4));
    if (!account) {
        Context.setVariable("account_balance_information", "ACCOUNT_NOT_FOUND");
        return;
    }

    // Extract account details
    const account_number_last4 = account.accountNumber.slice(-4);
    const account_id = account.id;
    Context.setVariable("account_id", account_id);
    const account_type = account.type?.toLowerCase();
    const account_status = account.status?.toLowerCase();
    const account_nickname = account.nickname || "";
    const currencySymbol = currencyMap[account.currency] || account.currency || "";

    // Handle special account types
    if (account_type && account_type.includes("credit")) {
        account_balance_information = "I can't provide balance information for credit accounts. Please route to Credit Card Agent.";
    } else if (account_type && account_type.includes("loan")) {
        account_balance_information = "I can't provide balance information for loan accounts. Please route to Loan Services Agent.";
    } else {
        // Get customer ID and check authentication
        const customer_id = getCustomerId();
        if (!customer_id) {
            Context.setVariable("account_balance_information", "Customer is not authenticated.");
            return;
        }

        const accountAccess = account.accountAccess || [];

        // ✅ Include HOLDER, OTAX, and OWN as valid access types
        const hasAccess = accountAccess.some(item =>
            item.customerId === customer_id &&
            (item.accessType === "OTAX" || item.accessType === "OWN" || item.accessType === "HOLDER")
        );

        if (!hasAccess) {
            Context.setVariable("account_balance_information", "You do not have access to the account balance of this account.");
            return;
        }

        const account_balance = account.balance;
        const account_available_balance = account.availableBalance;

        // Format response based on channel type
        if (isDigital) {
            account_balance_information = [
                `Your ${account_status} ${account_type} account ${account_nickname} ending in ${account_number_last4}:`,
                `- Available balance: ${currencySymbol}${account_available_balance}`,
                `- Current balance: ${currencySymbol}${account_balance}`
            ].join("\n");
        } else {
            account_balance_information = `For your ${account_nickname} account ending in ${account_number_last4}, your available balance is ${currencySymbol}${account_available_balance}, and your current balance is ${currencySymbol}${account_balance}.`;
        }
    }

    // Set the final balance information in context
    Context.setVariable("account_balance_information", account_balance_information);
}

