function parseDateInput(dateStr) {
    if (!dateStr) {
        return { ok: false, error: "missing" };
    }

    var s = ("" + dateStr).trim();
    var d;
    var y;
    var m;
    var day;
    var matchedFormat = "";

    // YYYY-MM-DD
    if (s.indexOf("-") > -1) {
        var parts = s.split("-");
        if (parts.length === 3) {
            y = parseInt(parts[0], 10);
            m = parseInt(parts[1], 10);
            day = parseInt(parts[2], 10);
            matchedFormat = "YYYY-MM-DD";
        }
    } else if (/^\d{8}$/.test(s)) {
        // 8 digits could be YYYYMMDD or MMDDYYYY.
        // Prefer YYYYMMDD when it looks like a real year/month/day.
        var y1 = parseInt(s.substring(0, 4), 10);
        var m1 = parseInt(s.substring(4, 6), 10);
        var d1 = parseInt(s.substring(6, 8), 10);

        if (y1 >= 1900 && y1 <= 2100 && m1 >= 1 && m1 <= 12 && d1 >= 1 && d1 <= 31) {
            y = y1;
            m = m1;
            day = d1;
            matchedFormat = "YYYYMMDD";
        } else {
            // Fallback: MMDDYYYY
            var m2 = parseInt(s.substring(0, 2), 10);
            var d2 = parseInt(s.substring(2, 4), 10);
            var y2 = parseInt(s.substring(4, 8), 10);
            y = y2;
            m = m2;
            day = d2;
            matchedFormat = "MMDDYYYY";
        }
    } else {
        // Unsupported format
        return { ok: false, error: "invalid_format" };
    }

    if (!matchedFormat) {
        return { ok: false, error: "invalid_format" };
    }

    if (isNaN(y) || isNaN(m) || isNaN(day) || y < 1900 || y > 2100 || m < 1 || m > 12 || day < 1 || day > 31) {
        return { ok: false, error: "invalid" };
    }

    d = new Date(y, m - 1, day);

    if (!d || isNaN(d.getTime())) {
        return { ok: false, error: "invalid" };
    }

    // Strict validation: reject non-existent dates like 2026-02-30
    if (d.getFullYear() !== y || (d.getMonth() + 1) !== m || d.getDate() !== day) {
        return { ok: false, error: "non_existent" };
    }

    d.setHours(0, 0, 0, 0);
    var mm = ("0" + (d.getMonth() + 1)).slice(-2);
    var dd = ("0" + d.getDate()).slice(-2);
    var formatted = d.getFullYear() + "-" + mm + "-" + dd;

    return { ok: true, date: d, formatted: formatted, inputFormat: matchedFormat };
}

