function getCountryCodes(countryNameCsv) {
    var names = ("" + countryNameCsv).split(",");
    var codes = [];

    for (var i = 0; i < names.length; i++) {
        var raw = names[i].trim();
        var key = raw.toLowerCase();
        var code = countryCodeMap[key];

        if (!code) {
            return { ok: false, unmatched: raw };
        }
        codes.push(code);
    }

    return { ok: true, codes: codes.join(", ") };
}

function getPhoneDigits(phone) {
    return phone ? ("" + phone).replace(/\D/g, "") : "";
}

(function main() {
    // Require country name
    if (!travel_country_name || !("" + travel_country_name).trim()) {
        warn("Missing travel country name", "What country (or countries) are you traveling to?");
        return;
    }

    // Check 1: Convert country names to country codes
    var cc = getCountryCodes(travel_country_name);
    if (!cc.ok) {
        warn("Country not recognized: " + cc.unmatched, "Just to confirm, which country is " + cc.unmatched + "?");
        return;
    }
    Context.setVariable("travel_country_code", cc.codes);

    // Check 2: Validate travel_start_date is today or in the future
    var today = new Date();
    today.setHours(0, 0, 0, 0);

    var startParsed = parseDateInput(travel_start_date);
    if (!startParsed.ok) {
        warn(
            "Start date is invalid or does not exist",
            "I need a start date, and it must be a valid date.\n" +
                "Please provide it in MMDDYYYY format (example: 02282026).\n" +
                "When does your travel begin?"
        );
        return;
    }
    var startDate = startParsed.date;
    travel_start_date = startParsed.formatted;
    Context.setVariable("travel_start_date", travel_start_date);

    if (startDate < today) {
        warn("Start date must be today or in the future", "I need a start date that's today or in the future.\nWhen does your travel begin?");
        return;
    }

    // Check 3: Validate travel_end_date and duration
    var endParsed = parseDateInput(travel_end_date);
    if (!endParsed.ok) {
        warn(
            "End date is invalid or does not exist",
            "I need an end date, and it must be a valid date.\n" +
                "Please provide it in MMDDYYYY format (example: 03012026).\n" +
                "When does your travel end?"
        );
        return;
    }
    var endDate = endParsed.date;
    travel_end_date = endParsed.formatted;
    Context.setVariable("travel_end_date", travel_end_date);

    if (endDate < startDate) {
        warn("End date must be on or after start date", "The end date must be on or after the start date.\nWhen does your travel end?");
        return;
    }

    var durationMs = endDate.getTime() - startDate.getTime();
    var durationDays = Math.floor(durationMs / (1000 * 60 * 60 * 24));

    if (durationDays > 184) {
        var sixMonthsDate = new Date(startDate);
        sixMonthsDate.setMonth(sixMonthsDate.getMonth() + 6);

        var sixMonth = ("0" + (sixMonthsDate.getMonth() + 1)).slice(-2);
        var sixDay = ("0" + sixMonthsDate.getDate()).slice(-2);
        var sixMonthsStr = sixMonthsDate.getFullYear() + "-" + sixMonth + "-" + sixDay;

        warn(
            "Travel duration exceeds 6 months maximum",
            "I can set up travel notifications for up to 6 months.\n" +
                "Would you like me to set the notification through " + sixMonthsStr + ",\n" +
                "and you can call us again to extend it if needed?"
        );
        return;
    }

    // Require a usable travel phone number: either a phone number or USE_PHONE_NUMBER_ON_FILE
    var phoneToken = travel_phone_number ? ("" + travel_phone_number).trim() : "";
    var phoneDigits = getPhoneDigits(phoneToken);
    var usePhoneOnFile = phoneToken === "USE_PHONE_NUMBER_ON_FILE";
    var hasValidPhoneDigits = phoneDigits && phoneDigits.length >= 4;

    if (!usePhoneOnFile && !hasValidPhoneDigits) {
        warn(
            "Missing or invalid travel phone number",
            "What is the best phone number to reach you while traveling?\n" +
                "Please provide a phone number, or enter USE_PHONE_NUMBER_ON_FILE."
        );
        return;
    }

    // All required checks passed
    var contactNumberPhrase = "";
    if (usePhoneOnFile) {
        contactNumberPhrase = "The contact number while traveling will be the phone number on file.";
    } else {
        var phoneLast4 = phoneDigits.slice(-4);
        contactNumberPhrase = "The contact number while traveling ends in " + phoneLast4 + ".";
    }

    var preSubmitNotice =
        "Before I submit this, I need to let you know:\n" +
        "Even with a travel notification, your card activity will still be monitored for potential fraud,\n" +
        "and you may be contacted by our Fraud Alert Management team to verify transactions.\n" +
        "The travel indicator does not exempt your card from fraud monitoring.\n\n";

    var totalCount = parseInt(account_total_count, 10);
    if (isNaN(totalCount)) {
        totalCount = 0;
    }

    var identifierPhrase = "";
    if (totalCount > 1 && card_identifier_type && card_identifier_value) {
        identifierPhrase = " And your " + card_identifier_type + " is " + card_identifier_value + ".";
    }

    travel_summary_info =
        preSubmitNotice +
        "Let me confirm the travel details. You're traveling to " +
        travel_country_name +
        " from " +
        travel_start_date +
        " through " +
        travel_end_date +
        ". " +
        contactNumberPhrase +
        identifierPhrase +
        " Is that correct?";
    Context.setVariable("travel_summary_info", travel_summary_info);
    setSkillResult("success", "gather travel information successfully", travel_summary_info);
