} else {
    // Get current date for expiration check
    var today = new Date();
    today.setHours(0, 0, 0, 0);

    // Search for matching identification (normalize to string, trim, case-insensitive)
    var matchedId = null;
    var normalizedPending = customer_identification_number ? ("" + customer_identification_number).trim().toUpperCase() : "";

    for (var i = 0; i < identifications.length; i++) {
        var recordNumber = identifications[i].number_ ? ("" + identifications[i].number_).trim().toUpperCase() : "";
        if (recordNumber === normalizedPending) {
