// Main normalization function
function normalizeAgentVariables() {

    // 1️⃣ Get ai_agent_variables safely
    let agentVars = parseIfJson(Context.getVariable("ai_agent_variables"));

    // 2️⃣ Extract with safe fallback to Context
    let sourcePhone =
        agentVars.source_phone ||
        Context.getVariable("source_phone");

    let lineType =
        agentVars.line_type ||
        Context.getVariable("line_type");

    // IMPORTANT: use ?? for boolean so false is preserved
    let returnToAutopilot =
        agentVars.return_to_autopilot ??
        Context.getVariable("return_to_autopilot");

    // Optional separate variable
    let sessionReason = Context.getVariable("session_reason");

    // 3️⃣ Set source_phone if exists
    if (sourcePhone) {
        Context.setVariable("source_phone", sourcePhone);
    }

    // 4️⃣ Normalize line_type (default = mobile)
    if (typeof lineType === "string" && lineType.trim() !== "") {
        Context.setVariable("line_type", lineType.toLowerCase());
    } else {
        Context.setVariable("line_type", "mobile");
    }

    // 5️⃣ Preserve session_reason
    if (sessionReason) {
        Context.setVariable("session_reason", sessionReason);
    }

    // 6️⃣ Preserve boolean correctly
    if (returnToAutopilot !== undefined && returnToAutopilot !== null) {
        Context.setVariable("return_to_autopilot", returnToAutopilot);
    }

    // 7️⃣ Optional: return debug object
    return {
        source_phone: sourcePhone || null,
        line_type: lineType || "mobile",
        return_to_autopilot: returnToAutopilot ?? null
    };
}

